49	  typedef logic [AxiDataWidth-1:0] data_t; // for sign extension
50	
51	  typedef enum addr_t {
52	    MBOXW  = addr_t'(0 * AxiDataWidth/8),
53	    MBOXR  = addr_t'(1 * AxiDataWidth/8),
54	    STATUS = addr_t'(2 * AxiDataWidth/8),
55	    ERROR  = addr_t'(3 * AxiDataWidth/8),
56	    WIRQT  = addr_t'(4 * AxiDataWidth/8),
57	    RIRQT  = addr_t'(5 * AxiDataWidth/8),
58	    IRQS   = addr_t'(6 * AxiDataWidth/8),
59	    IRQEN  = addr_t'(7 * AxiDataWidth/8),
60	    IRQP   = addr_t'(8 * AxiDataWidth/8),
61	    CTRL   = addr_t'(9 * AxiDataWidth/8)
62	  } reg_addr_e;
63	
64	  typedef axi_test::axi_lite_rand_master #(
