299	    // -------------------------------
300	    repeat (50) @(posedge clk);
301	    $info("%0t MST_0> Make an unmapped access read and write ", $time());
302	    lite_axi_master.read(addr_t'(16'hDEAD), axi_pkg::prot_t'('0), data, resp);
303	    assert (resp == axi_pkg::RESP_SLVERR) else begin test_failed[0]++; $error("Unexpected result"); end
304	    lite_axi_master.write(addr_t'(16'hDEAD), axi_pkg::prot_t'('0), data_t'(16'hDEAD), 8'hFF, resp);
305	    assert (resp == axi_pkg::RESP_SLVERR) else begin test_failed[0]++; $error("Unexpected result"); end
306	    lite_axi_master.write(ERROR, axi_pkg::prot_t'('0), data_t'(16'hDEAD), 8'hFF, resp);
307	    assert (resp == axi_pkg::RESP_SLVERR) else begin test_failed[0]++; $error("Unexpected result"); end
308	    lite_axi_master.write(IRQEN, axi_pkg::prot_t'('0), data_t'(16'hDEAD), 8'h00, resp);
309	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[0]++; $error("Unexpected result"); end
310	    lite_axi_master.write(IRQS, axi_pkg::prot_t'('0), data_t'(16'hDEAD), 8'h00, resp);
311	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[0]++; $error("Unexpected result"); end
312	    lite_axi_master.write(WIRQT, axi_pkg::prot_t'('0), data_t'('1), 8'h00, resp);
313	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[0]++; $error("Unexpected result"); end
314	    lite_axi_master.write(WIRQT, axi_pkg::prot_t'('0), data_t'('1), 8'hFF, resp);
315	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[0]++; $error("Unexpected result"); end
316	    lite_axi_master.write(WIRQT, axi_pkg::prot_t'('0), data_t'('0), 8'hFF, resp);
317	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[0]++; $error("Unexpected result"); end
318	    lite_axi_master.write(RIRQT, axi_pkg::prot_t'('0), data_t'('1), 8'h00, resp);
319	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[0]++; $error("Unexpected result"); end
320	    lite_axi_master.write(RIRQT, axi_pkg::prot_t'('0), data_t'('1), 8'hFF, resp);
321	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[0]++; $error("Unexpected result"); end
322	    lite_axi_master.write(WIRQT, axi_pkg::prot_t'('0), data_t'('0), 8'hFF, resp);
323	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[0]++; $error("Unexpected result"); end
324	
325	    end_of_sim[0] <= 1'b1;
326	  end
327	
328	  initial begin : proc_master_1
329	    automatic rand_lite_master_t lite_axi_master = new ( master_dv[1], "MST_1");
330	    //automatic int unsigned    test_failed = 0;
331	    automatic data_t          data        = '0;
332	    automatic axi_pkg::resp_t resp        = axi_pkg::RESP_SLVERR;
333	    automatic int unsigned    loop        = 0;
334	    end_of_sim[1] <= 1'b0;
335	    lite_axi_master.reset();
336	    @(posedge rst_n);
337	
338	    // -------------------------------
339	    // Test Flush seperately
340	    // -------------------------------
341	    $display("%0t MST_1> Flush Read MBOX ", $time());
342	    lite_axi_master.write(CTRL, axi_pkg::prot_t'('0), data_t'(2'b10), 8'hFF, resp);
343	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
344	
345	    $display("%0t MST_1> Flush Write MBOX ", $time());
346	    lite_axi_master.write(CTRL, axi_pkg::prot_t'('0), data_t'(2'b01), 8'hFF, resp);
347	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
348	
349	    // -------------------------------
350	    // Set read and write thresholds, wait for reflect some data
351	    // -------------------------------
352	    $display("%0t MST_1> Set Read threshold to 64'd0 ", $time());
353	    lite_axi_master.write(RIRQT, axi_pkg::prot_t'('0), data_t'(0), 8'hFF, resp);
354	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
355	
356	    $display("%0t MST_1> Enable Read threshold interrupt  ", $time());
357	    lite_axi_master.write(IRQEN, axi_pkg::prot_t'('0), data_t'(2), 8'hFF, resp);
358	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
359	
360	    $display("%0t MST_1> Wait for Read threshold interrupt  ", $time());
361	    wait (irq[1]);
362	    $display("%0t MST_1> Interrupt Recieved, read pending register and Acknowledge irq ", $time());
363	    lite_axi_master.read(IRQP, axi_pkg::prot_t'('0), data, resp);
364	    assert (data == data_t'(2)) else begin test_failed[1]++; $error("Unexpected result"); end
365	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
366	    lite_axi_master.read(IRQS, axi_pkg::prot_t'('0), data, resp);
367	    assert (data == data_t'(2)) else begin test_failed[1]++; $error("Unexpected result"); end
368	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
369	    lite_axi_master.read(MBOXR, axi_pkg::prot_t'('0), data, resp);
370	    assert (data == data_t'(32'hFEEDFEED)) else begin test_failed[1]++; $error("Unexpected result"); end
371	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
372	    lite_axi_master.write(IRQS, axi_pkg::prot_t'('0), data_t'(2), 8'h1, resp);
373	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
374	
375	    $display("%0t MST_1> Enable write threshold interrupt ", $time());
376	    lite_axi_master.write(WIRQT, axi_pkg::prot_t'('0), 32'h8, 8'h1, resp);
377	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
378	    lite_axi_master.write(IRQEN, axi_pkg::prot_t'('0), data_t'(1), 8'hFF, resp);
379	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
380	
381	    $display("%0t MST_1> Write back looping answer ", $time());
382	    while (!irq[1]) begin
383	      lite_axi_master.write(MBOXW, axi_pkg::prot_t'('0), data_t'(loop), 8'hFF, resp);
384	      assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
385	      loop++;
386	    end
387	    $display("%0t MST_1> Stop looping answer and clear interrupt", $time());
388	    lite_axi_master.read(IRQP, axi_pkg::prot_t'('0), data, resp);
389	    assert (data == data_t'(1)) else begin test_failed[1]++; $error("Unexpected result"); end
390	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
391	    lite_axi_master.read(IRQS, axi_pkg::prot_t'('0), data, resp);
392	    assert (data == data_t'(1)) else begin test_failed[1]++; $error("Unexpected result"); end
393	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
394	    // clear the interrupt, if the Write FIFO is status reg is below threshold
395	    lite_axi_master.read(STATUS, axi_pkg::prot_t'('0), data, resp);
396	    while (data[3]) begin
397	      repeat (10) @(posedge clk);
398	      lite_axi_master.read(STATUS, axi_pkg::prot_t'('0), data, resp);
399	      assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
400	    end
401	    lite_axi_master.write(IRQS, axi_pkg::prot_t'('0), data_t'(2), 8'h1, resp);
402	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
403	    lite_axi_master.write(IRQEN, axi_pkg::prot_t'('0), data_t'(0), 8'h1, resp);
404	    assert (resp == axi_pkg::RESP_OKAY) else begin test_failed[1]++; $error("Unexpected result"); end
405	
406	    end_of_sim[1] <= 1'b1;
407	  end
408	
409	  initial begin : proc_monitor_irq_0
410	    forever begin
411	      @(posedge irq[0]);
412	      $info("Recieved interrupt from slave port 0");
413	    end
414	  end
415	
416	  initial begin : proc_monitor_irq_1
417	    forever begin
418	      @(posedge irq[1]);
419	      $info("Recieved interrupt from slave port 1");
420	    end
421	  end
422	
423	  initial begin : proc_stop_sim
424	    wait (&end_of_sim);
425	    repeat (50) @(posedge clk);
426	    $display("Slave port 0 failed tests: %0d", test_failed[0]);
427	    $display("Slave port 1 failed tests: %0d", test_failed[1]);
428	    if (test_failed[0] > 0 || test_failed[1] > 0) begin
429	        $fatal(1, "Simulation stopped as assertion errors have been encountered, Failure!!!");
430	    end else begin
431	        $info("Simulation stopped as all Masters transferred their data, Success.",);
432	    end
433	    $stop();
434	  end
435	
436	  //-----------------------------------
437	  // Clock generator
438	  //-----------------------------------
439	  clk_rst_gen #(
440	    .ClkPeriod    ( CyclTime ),
441	    .RstClkCycles ( 5        )
442	  ) i_clk_gen (
443	    .clk_o (clk),
444	    .rst_no(rst_n)
445	  );
446	
447	  //-----------------------------------
448	  // DUT
449	  //-----------------------------------
450	  axi_lite_mailbox_intf #(
451	    .MAILBOX_DEPTH  ( MailboxDepth ),
452	    .IRQ_EDGE_TRIG  ( 1'b0         ),
453	    .IRQ_ACT_HIGH   ( 1'b1         ),
454	    .AXI_ADDR_WIDTH ( AxiAddrWidth ),
455	    .AXI_DATA_WIDTH ( AxiDataWidth )
456	  ) i_mailbox_dut (
457	    .clk_i       ( clk       ),
458	    .rst_ni      ( rst_n     ),
459	    .test_i      ( 1'b0      ),
460	    .slv         ( master    ),
461	    .irq_o       ( irq       ),
462	    .base_addr_i ( '0        ) // set base address to '0
463	  );
464	endmodule
